import{_ as t,o,c as a,a3 as s}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"80. Study Leave","description":"","frontmatter":{"title":"80. Study Leave","eba":"Allied Health Professionals 2021-2026","topics":["leave","study-leave","employment"]},"headers":[],"relativePath":"ebas/allied-health/education-pd/80-study-leave.md","filePath":"ebas/allied-health/education-pd/80-study-leave.md"}'),n={name:"ebas/allied-health/education-pd/80-study-leave.md"};function r(l,e,i,p,d,h){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="_80-study-leave" tabindex="-1">80. Study Leave <a class="header-anchor" href="#_80-study-leave" aria-label="Permalink to &quot;80. Study Leave&quot;">​</a></h1><p><strong>80.1</strong> Amount of Study Leave</p><p><strong>(a)</strong> Paid study leave is available to all Employees employed in full-time and part-time employment.</p><p><strong>(b)</strong> Paid study leave may be taken as agreed between the Employer and Employee; for example, four (4) hours per week, eight (8) hours per fortnight or blocks of 38 hours at a residential school.</p><p><strong>80.2</strong> Application Process</p><p><strong>(a)</strong> Study Leave is available on written application by the Employee. The application should be made as early possible prior to the proposed leave date.</p><p><strong>(b)</strong> The application will include:</p><p><strong>(i)</strong> details of the course and institution in which the Employee is enrolled or proposes to enrol; and</p><p><strong>(ii)</strong> details of the relevance of the course to the Employee&#39;s profession.</p><p><strong>80.3</strong> Response to Application</p><p><strong>(a)</strong> The Employer may refuse to grant an Employee study leave only where there are reasonable grounds for doing so.</p><p><strong>(b)</strong> The Employer must notify the Employee in writing of whether the leave has been approved within seven (7) days of the request being made.</p><p><strong>(c)</strong> If the leave is not approved, the reasons will be included in the written notification to the Employee.</p><p><strong>(d)</strong> Once study leave has been granted by the Employer it will not be revoked unless mutually agreed which may be at the request of the Employee, save that the Employer will not unreasonably refuse a request by an Employee to revoke the granting of leave.</p>',14)])])}const m=t(n,[["render",r]]);export{y as __pageData,m as default};
